#include <iostream>
#include <ctime>     // For time() function in C++ 
                    
void logError(const std::string& errorMessage) {  
    char buffer[80];                 
    std::time_t result = std::time(nullptr);     
	std::strftime(buffer, sizeof(buffer), "%d-%m-%Y %H:%M:%S", &result);  // Get current date and time  
        
	// Print the timestamp on top of error message.   
     std::cout << buffer <<  " - Error Message :"<< "\n";     
	std::cout  <<errorMessage;      
}